                new java.util.HashSet<>(java.util.Arrays.asList("D", "E")));
        ServiceInfo serviceInfo = new ServiceInfo();
        serviceInfo.setGroupName("B");
        serviceInfo.setName("C");
        Instance instanceD = new Instance();
        instanceD.setClusterName("D");
        instanceD.setIp("1.1.1.1");
        Instance instanceE = new Instance();
        instanceE.setClusterName("E");
        instanceE.setIp("2.2.2.2");
        Instance instanceD2 = new Instance();
        instanceD2.setClusterName("D");
        instanceD2.setIp("3.3.3.3");
